/**
 * Sutter Import Integration Tests
 *
 * Exercises the full Sutter pipeline (parse → map → transform → validate → diff)
 * using programmatically-generated Excel fixture files in test-data/.
 *
 * Fixtures are generated by: npx tsx test-data/create-sutter-fixtures.ts
 * Must be run before these tests. Files:
 *   test-sutter-valid.xlsx        - Happy path, all 10 action patterns
 *   test-sutter-duplicates.xlsx   - Same patient+measure merging
 *   test-sutter-edge-cases.xlsx   - Special chars, dates, missing fields
 *   test-sutter-errors.xlsx       - Validation failures
 *   test-sutter-skip-actions.xlsx - All skipActions + 2 valid
 *   test-sutter-unmapped.xlsx     - Unmapped action aggregation
 *   test-sutter-merge.xlsx        - Merge/replace against existing records
 *   test-sutter-measure-details.xlsx - Measure details parsing
 */

import { describe, it, expect, beforeAll } from '@jest/globals';
import * as fs from 'fs';
import * as path from 'path';
import { fileURLToPath } from 'url';
import { parseExcel, getSheetNames } from '../fileParser.js';
import { mapColumns } from '../columnMapper.js';
import { transformData } from '../dataTransformer.js';
import { validateRows } from '../validator.js';
import {
  calculateMergeDiff,
  type ExistingRecord,
  type DiffSummary,
} from '../diffCalculator.js';
import type { SutterTransformResult } from '../sutterDataTransformer.js';

// ESM-compatible __dirname
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const FIXTURES_DIR = path.join(__dirname, '../../../../../test-data');

function readFixture(filename: string): Buffer {
  return fs.readFileSync(path.join(FIXTURES_DIR, filename));
}

/** Run the full pipeline: parse → map → transform for a given sheet */
function pipeline(buffer: Buffer, sheetName: string) {
  const parsed = parseExcel(buffer, 'test.xlsx', { sheetName, headerRow: 3 });
  const mapping = mapColumns(parsed.headers, 'sutter');
  const result = transformData(parsed.headers, parsed.rows, 'sutter', parsed.dataStartRow);
  return result as SutterTransformResult;
}

function emptySummary(): DiffSummary {
  return { inserts: 0, updates: 0, skips: 0, duplicates: 0, deletes: 0 };
}

// ─────────────────────────────────────────────────────────────────
// Verify fixtures exist before running tests
// ─────────────────────────────────────────────────────────────────
const FIXTURE_FILES = [
  'test-sutter-valid.xlsx',
  'test-sutter-duplicates.xlsx',
  'test-sutter-edge-cases.xlsx',
  'test-sutter-errors.xlsx',
  'test-sutter-skip-actions.xlsx',
  'test-sutter-unmapped.xlsx',
  'test-sutter-merge.xlsx',
  'test-sutter-measure-details.xlsx',
];

beforeAll(() => {
  for (const file of FIXTURE_FILES) {
    const filePath = path.join(FIXTURES_DIR, file);
    if (!fs.existsSync(filePath)) {
      throw new Error(
        `Missing fixture: ${filePath}\nRun: cd backend && npx tsx ../test-data/create-sutter-fixtures.ts`
      );
    }
  }
});

// ─────────────────────────────────────────────────────────────────
// 1. test-sutter-valid.xlsx
// ─────────────────────────────────────────────────────────────────
describe('test-sutter-valid.xlsx', () => {
  let buffer: Buffer;

  beforeAll(() => {
    buffer = readFixture('test-sutter-valid.xlsx');
  });

  it('should discover 4 sheets with 2 physician tabs and 2 skip tabs', () => {
    const sheets = getSheetNames(buffer);
    expect(sheets).toEqual(['Physician One', 'Physician Two', 'CAR Report', 'Summary_NY']);
  });

  it('should parse Physician One tab with 21 data rows', () => {
    const parsed = parseExcel(buffer, 'test.xlsx', { sheetName: 'Physician One', headerRow: 3 });
    expect(parsed.rows).toHaveLength(21);
  });

  it('should merge AWV + APV for Anderson, Jane into single AWV row', () => {
    const result = pipeline(buffer, 'Physician One');
    const andersonAWV = result.rows.filter(
      r => r.memberName === 'Anderson, Jane' && r.requestType === 'AWV'
    );
    // AWV + APV = 2 input rows, but after merge -> 1 output row
    expect(andersonAWV).toHaveLength(1);
    expect(andersonAWV[0].qualityMeasure).toBe('Annual Wellness Visit');
  });

  it('should map HCC row for Anderson, Jane with notes', () => {
    const result = pipeline(buffer, 'Physician One');
    const andersonHCC = result.rows.find(
      r => r.memberName === 'Anderson, Jane' && r.requestType === 'Chronic DX'
    );
    expect(andersonHCC).toBeDefined();
    expect(andersonHCC!.qualityMeasure).toBe('Chronic Diagnosis Code');
    expect((andersonHCC as any).notes).toBe('HCC coding: review diagnosis Z99.1');
  });

  it('should map all 10 action patterns correctly', () => {
    const result = pipeline(buffer, 'Physician One');
    const measures = result.rows.map(r => r.qualityMeasure);

    // Colon Cancer Screening (FOBT)
    expect(measures).toContain('Colon Cancer Screening');
    // Hypertension Management (HTN)
    expect(measures).toContain('Hypertension Management');
    // Diabetic Nephropathy (DM urine albumin)
    expect(measures).toContain('Diabetic Nephropathy');
    // Diabetes Control (DM HbA1c)
    expect(measures).toContain('Diabetes Control');
    // Diabetic Eye Exam (DM Eye)
    expect(measures).toContain('Diabetic Eye Exam');
    // Cervical Cancer Screening (Pap/HPV)
    expect(measures).toContain('Cervical Cancer Screening');
    // Breast Cancer Screening (Mammogram)
    expect(measures).toContain('Breast Cancer Screening');
    // GC/Chlamydia Screening (Chlamydia)
    expect(measures).toContain('GC/Chlamydia Screening');
    // ACE/ARB in DM or CAD (RAS Antagonists)
    expect(measures).toContain('ACE/ARB in DM or CAD');
    // Vaccination (Vaccine)
    expect(measures).toContain('Vaccination');
  });

  it('should set measureStatus to "Not Addressed" for all Quality rows', () => {
    const result = pipeline(buffer, 'Physician One');
    const qualityRows = result.rows.filter(
      r => r.requestType !== 'AWV' && r.requestType !== 'Chronic DX'
    );
    for (const row of qualityRows) {
      expect(row.measureStatus).toBe('Not Addressed');
    }
  });

  it('should merge Vaccine rows for Green, Robert (same patient, same quality measure)', () => {
    const result = pipeline(buffer, 'Physician One');
    const greenVaccine = result.rows.filter(
      r => r.memberName === 'Green, Robert' && r.qualityMeasure === 'Vaccination'
    );
    // Two vaccine rows (Flu + Pneumococcal) -> merged into 1
    expect(greenVaccine).toHaveLength(1);
    const actionText = (greenVaccine[0] as any).sourceActionText || '';
    expect(actionText).toContain('Flu');
    expect(actionText).toContain('Pneumococcal');
  });

  it('should parse HbA1c measure details correctly (date + tracking1)', () => {
    const result = pipeline(buffer, 'Physician One');
    const diabetesRow = result.rows.find(
      r => r.memberName === 'Clark, Maria' && r.qualityMeasure === 'Diabetes Control'
    );
    expect(diabetesRow).toBeDefined();
    expect(diabetesRow!.statusDate).toBe('2025-01-10');
    expect((diabetesRow as any).tracking1).toBe('7.5');
  });

  it('should parse comma-separated dates (latest wins) for Harris, Pat', () => {
    const result = pipeline(buffer, 'Physician One');
    const harrisColon = result.rows.find(
      r => r.memberName === 'Harris, Pat' && r.qualityMeasure === 'Colon Cancer Screening'
    );
    expect(harrisColon).toBeDefined();
    // '01/15/2025, 03/20/2025' -> latest is 03/20/2025 -> 2025-03-20
    expect(harrisColon!.statusDate).toBe('2025-03-20');
  });

  it('should have zero unmapped actions for Physician One', () => {
    const result = pipeline(buffer, 'Physician One');
    expect(result.unmappedActions).toHaveLength(0);
  });

  it('should produce correct stats for Physician One', () => {
    const result = pipeline(buffer, 'Physician One');
    expect(result.stats.inputRows).toBe(21);
    // 21 rows - 2 merged (AWV+APV for Anderson) - 1 merged (2 Vaccines for Green)
    //         - 1 merged (2 Depression Screening for Hill)
    // Anderson: AWV+APV+HCC = 3 input -> 2 output (AWV merged, HCC separate)
    // Baker: 2 Quality = 2 output
    // Clark: 3 Quality = 3 output
    // Davis: 2 Quality = 2 output
    // Evans: 1 Quality = 1 output
    // Foster: 1 Quality = 1 output
    // Green: 2 Quality (both Vaccination) = 1 output (merged)
    // Hill: 2 Quality (both Depression Screening) = 1 output (merged)
    // James: 1 Quality (Depression Screening) = 1 output
    // Harris: AWV + Quality = 2 output
    // Irving: 2 Quality (Mammogram + Vaccine = different measures) = 2 output
    // Total: 2+2+3+2+1+1+1+1+1+2+2 = 18
    expect(result.stats.outputRows).toBe(18);
    expect(result.stats.errorCount).toBe(0);
  });

  it('should process Physician Two tab correctly', () => {
    const result = pipeline(buffer, 'Physician Two');
    expect(result.stats.inputRows).toBe(9);
    expect(result.stats.errorCount).toBe(0);
    expect(result.rows.length).toBeGreaterThan(0);

    // Check HCC for Lewis, Dan
    const lewisHCC = result.rows.find(
      r => r.memberName === 'Lewis, Dan' && r.requestType === 'Chronic DX'
    );
    expect(lewisHCC).toBeDefined();
    expect((lewisHCC as any).notes).toBe('HCC coding: diagnosis E11.9');
  });

  it('should produce all INSERTs when diff against empty existing data', () => {
    const result = pipeline(buffer, 'Physician One');
    const summary = emptySummary();
    const changes = calculateMergeDiff(result.rows, new Map(), summary);
    expect(summary.inserts).toBe(result.rows.length);
    expect(changes.every(c => c.action === 'INSERT')).toBe(true);
  });
});

